      conflict_flag: base.conflict_flag === true,
    }),
  },
}];

const response = typeof $json.response_json_text === 'string'
  ? JSON.parse($json.response_json_text)
  : $json;
const session = response.session ?? {
  turn_count_before: 0,
  history_used: false,
  stored: false,
};
const trace = response.trace ?? null;
const withStage = (existingTrace, stage, status, extra = {}) => {
  if (!existingTrace) {
    return null;
  }
  const timestamp = new Date().toISOString();
  const errorCode = Object.prototype.hasOwnProperty.call(extra, 'error_code') ? extra.error_code : (existingTrace.error_code ?? null);
  const errorMessage = Object.prototype.hasOwnProperty.call(extra, 'error_message') ? extra.error_message : (existingTrace.error_message ?? null);
  return {
    ...existingTrace,
    ...extra,
    stage,
    status,
    error_code: errorCode,
    error_message: errorMessage,
    timestamp,
    stage_history: [
      ...(Array.isArray(existingTrace.stage_history) ? existingTrace.stage_history : []),
      { stage, status, timestamp, error_code: errorCode, error_message: errorMessage },
    ],
  };
};
return [{
  json: {
    ...response,
    session: {
      ...session,
      stored: true,
      turn_count_after: (session.turn_count_before ?? 0) + 2,
    },
    trace: withStage(trace, 'stored', 'succeeded'),
  },
}];
